const items = $input.all();
const results = [];

for (const inputItem of items) {
  const item = inputItem.json;

  // Non-stock_check batch types pass through untouched
  if (item.batch_type !== 'stock_check') {
    results.push({ json: item });
    continue;
  }

  const products = (item.batch && item.batch.p) || [];

  // Convert stock_check -> sales directly
  // NOTE: Prepare Sales Items node ALREADY validates live stock from Google Sheet
  // and blocks sale if stock is 0. No need to validate here using agent's stock values.
  const salesBatch = products.map(p => ({
    sku_id:        p.sku ?? p.sku_id,
    product_name:  p.n   ?? p.product_name,
    quantity_sold: String(parseInt(String(p.r ?? p.requested_qty ?? 0).replace(/[^0-9]/g, '')) || 0)
  }));

  if (salesBatch.length === 0) {
    results.push({ json: { batch_type: 'none', output: item.output || '', batch: [], batch_count: 0 } });
    continue;
  }

  results.push({ json: {
    batch_type:  'sales',
    output:      item.output || '',
    batch: {
      sn: (item.batch && item.batch.sn) || '',
      sc: (item.batch && item.batch.sc) || '',
      p:  salesBatch
    },
    batch_count: salesBatch.length
  }});
}

return results;

const items = $input.all();

const saleWords = ['becha','beche','bechdiya','bech','sell','sold','sale','nikala','diya'];
const purchaseWords = ['kharida','kharide','kharidi','purchase','order','mangaya','aaya','liya','mangwaya'];

function hasWord(str, words) {
  return words.some(w => {
    const re = new RegExp('\\b' + w + '\\b', 'i');
    return re.test(str);
  });
}

return items.map(item => {
  const text = (item.json.chatInput || '').toString();
  const saleMatch = hasWord(text, saleWords);
  const purchaseMatch = hasWord(text, purchaseWords);

  let hint = 'NO_KEYWORD_DETECTED';
  if (saleMatch && !purchaseMatch) hint = 'SALE_KEYWORD_DETECTED';
  else if (purchaseMatch && !saleMatch) hint = 'PURCHASE_KEYWORD_DETECTED';
  else if (saleMatch && purchaseMatch) hint = 'AMBIGUOUS_BOTH_KEYWORDS_DETECTED';

  return { json: { ...item.json, keyword_hint: hint } };
});

const prepItems = $('Prepare Purchase Items1').all();
const items = $input.first().json.products || [];
const total = items.length;

const preview = items.slice(0,10).map((p, i) => {
  const name  = p.product_name || p.sku_id || '?';
  const stock = (p.current_stock !== undefined && p.current_stock !== '') ? p.current_stock : '?';

  // quantity_ordered survives in Prepare Purchase Items, not in aggregated Sheets output
  let qty = '?';
  if (prepItems[i]) {
    const pre = prepItems[i].json;
    qty = (pre.quantity_ordered && pre.quantity_ordered !== '0' && pre.quantity_ordered !== '')
          ? pre.quantity_ordered
          : '?';
  }

  const pre = prepItems[i] ? prepItems[i].json : {};
  const cost     = pre.price_at_purchase && pre.price_at_purchase !== '0' ? ` | Cost: ₹${pre.price_at_purchase}` : '';
  const totalCst = pre.total_cost && pre.total_cost !== '0' ? ` | Total: ₹${pre.total_cost}` : '';
  return `• ${name} — Ordered: ${qty} | New Stock: ${stock}${cost}${totalCst}`;
}).join('\n');

const more = total > 10 ? `\n...and ${total-10} more products` : '';
return [{json:{output:`✅ ${total} product(s) ka purchase record ho gaya!\n\n${preview}${more}\n\n📦 Inventory updated\n📋 PO Tracker updated`}}];

const raw = $('Route Batch Type1').first().json.batch;
const liveRows = $('Get Live Stock Purchase1').all().map(i => i.json);
const liveMap_sku = {};
const liveMap_name = {};
for (const r of liveRows) {
  if (r.sku_id) liveMap_sku[r.sku_id] = r;
  if (r.product_name) {
    const norm = String(r.product_name || '').toLowerCase().replace(/[^a-z0-9]/g, '').trim();
    liveMap_name[norm] = r;
  }
}

const today = new Date().toISOString().split('T')[0];
const ts    = new Date().toISOString();
let items, sn, sc;
if (Array.isArray(raw)) {
  items=raw; sn=''; sc='';
} else {
  sn=raw.sn||''; sc=String(raw.sc||''); items=raw.p||[];
}

if (!items || items.length === 0) {
  throw new Error('EMPTY_PURCHASE_BATCH: no items recovered from agent output');
}

return items.map((p,i) => {
  let sku, name, qtyOrdered, cat;
  if (Array.isArray(p)) {
    sku        = p[0];
    name       = p[1];
    qtyOrdered = p[2];
    cat = p[4] || 'General';
  } else {
    sku=p.sku_id; name=p.product_name||p.sku_id;
    qtyOrdered=p.quantity_ordered;
    cat=p.category||'General';
    sn=p.supplier_name||sn; sc=String(p.supplier_contact_number||sc);
  }

  qtyOrdered = (qtyOrdered !== null && qtyOrdered !== undefined && qtyOrdered !== '' && qtyOrdered !== '?')
               ? (parseInt(String(qtyOrdered).replace(/[^0-9]/g,'')) || 0)
               : 0;
  name = name || sku || 'Unknown';

  // ROOT-CAUSE FIX: current_stock comes from a fresh live sheet read, NEVER from the agent's own text output.
  // FALLBACK FIX: if the agent's sku_id doesn't exactly match the live sheet (e.g. it drifted from
  // chat memory instead of being copied fresh from a tool call this transaction — wrong case, a typo,
  // a reconstructed/hyphenated guess, stale value, etc.), fall back to a normalized product-name
  // match before giving up. This mirrors the same safety net Prepare Batch Items1 already uses for
  // the opposite mismatch (existing product wrongly routed as unmatched).
  const normName = String(name || '').toLowerCase().replace(/[^a-z0-9]/g, '').trim();
  const live = (sku && liveMap_sku[sku]) || liveMap_name[normName];

  // GRACEFUL FALLBACK: product not in sheet yet — treat as new product (generate SKU)
  let resolvedSku, resolvedName, liveStock;
  if (live) {
    resolvedSku  = live.sku_id;
    resolvedName = live.product_name || name;
    liveStock    = parseInt(String(live.current_stock).replace(/[^0-9]/g,'')) || 0;
  } else {
    resolvedSku  = sku || ('SKU-' + String(name || 'PRODUCT').toUpperCase().replace(/[^A-Z0-9]/g,'').slice(0,18) + '-' + String(i+1).padStart(4,'0'));
    resolvedName = name;
    liveStock    = 0;
  }
  const newStock = liveStock + qtyOrdered;

  // FIX: created_at was missing entirely from this object, leaving the PO Tracker's
  // created_at column blank for every "SENT" (existing-product reorder) row, even though
  // the "ORDERED" (new-product) path already fills it. Reuse the product's original
  // created_at if it already exists in the live sheet, otherwise fall back to today.
  const resolvedCreatedAt = (live && live.created_at) ? live.created_at : today;

  // Extract price_at_purchase from batch index 5
  let priceAtPurchase = 0;
  if (Array.isArray(p) && p[5] !== undefined && p[5] !== null && p[5] !== '') {
    priceAtPurchase = parseFloat(String(p[5]).replace(/[^0-9.]/g,'')) || 0;
  } else if (p && p.price_at_purchase !== undefined) {
    priceAtPurchase = parseFloat(String(p.price_at_purchase).replace(/[^0-9.]/g,'')) || 0;
  }
  const totalCost = priceAtPurchase * qtyOrdered;

  return {json:{
    sku_id:                 resolvedSku,
    product_name:           resolvedName,
    quantity_ordered:       String(qtyOrdered),
    current_stock:          String(newStock),
    category:               cat,
    supplier_name:          sn,
    supplier_contact_number:sc,
    created_at:             resolvedCreatedAt,
    po_number:              `PO-${today.replace(/-/g,'')}-${String(i+1).padStart(4,'0')}`,
    po_date:                today,
    estimated_delivery:     today,
    po_status:              'SENT',
    forecasted_demand:      '0',
    days_until_stockout:    '0',
    stock_added:            'NO',
    stock_added_at:         '',
    delivery_datetime:      '',
    last_updated:           ts,
    price_at_purchase:      String(priceAtPurchase),
    total_cost:             String(totalCost)
  }};
});

const prepItems = $('Prepare Sales Items1').all();
const items = $input.first().json.products || [];
const total = items.length;

// ZERO STOCK / SKU NOT FOUND: if ALL prep items are blocked, return user-friendly error
const blockedItems = prepItems.filter(i => i.json.__blocked === true);
if (blockedItems.length > 0 && blockedItems.length === prepItems.length) {
  const msgs = blockedItems.map(i => i.json._block_msg).filter(Boolean).join('\n');
  return [{json:{output: msgs || '\u274C Sale block ho gayi. Stock check karein.'}}];
}

// Mixed batch: some blocked, some valid
const validPrepItems = prepItems.filter(i => !i.json.__blocked);
const validItems = items.filter(i => i.status !== 'BLOCKED');
const processedTotal = validItems.length || validPrepItems.length;

const preview = validItems.slice(0,10).map((p, i) => {
  const name  = p.product_name || p.sku_id || '?';
  const stock = (p.current_stock !== undefined && p.current_stock !== '') ? p.current_stock : '?';
  let qty = '?';
  if (validPrepItems[i]) {
    const pre = validPrepItems[i].json;
    qty = (pre.quantity_sold && pre.quantity_sold !== '0' && pre.quantity_sold !== '')
          ? pre.quantity_sold
          : (pre.stock_deducted && pre.stock_deducted !== '0' ? pre.stock_deducted : '\u26A00');
  }
  const pre2 = validPrepItems[i] ? validPrepItems[i].json : {};
  const sPrice = pre2.price_at_sale && pre2.price_at_sale !== '0' ? ` | Price: ₹${pre2.price_at_sale}` : '';
  const sTotal = pre2.total_amount  && pre2.total_amount  !== '0' ? ` | Total: ₹${pre2.total_amount}`  : '';
  return `\u2022 ${name} \u2014 Sold: ${qty} | Remaining: ${stock}${sPrice}${sTotal}`;
}).join('\n');

const more = processedTotal > 10 ? `\n...and ${processedTotal-10} more products` : '';

// Note any blocked items in a mixed batch
let blockedNote = '';
if (blockedItems.length > 0) {
  const blockedMsgs = blockedItems.map(i => i.json._block_msg).filter(Boolean).join('\n');
  blockedNote = `\n\n\u26A0\uFE0F Kuch items block hue:\n${blockedMsgs}`;
}

return [{json:{output:`\u2705 ${processedTotal} product(s) ka sale record ho gaya!\n\n${preview}${more}\n\n\uD83D\uDCCA Sales Log updated\n\uD83D\uDCE6 Inventory updated${blockedNote}`}}];

const raw = $('Route Batch Type1').first().json.batch;
const today = new Date().toISOString().split('T')[0];
const ts    = new Date().toISOString();
const items = Array.isArray(raw) ? raw : (raw && raw.p ? raw.p : []);

// SOFT ERROR instead of throw — empty batch
if (!items || items.length === 0) {
  return [{json:{
    __blocked: true,
    _block_msg: '⚠️ Koi product nahi mila sale karne ke liye. Dobara try karein.',
    sku_id:'', product_name:'', category:'General',
    quantity_sold:'0', sale_date:today, source:'Chat', chat_id:'',
    stock_deducted:'0', processed_at:ts, message_text:'EMPTY_SALES_BATCH',
    sale_datetime:ts, status:'BLOCKED', new_stock:'0', current_stock:'0', last_updated:ts
  }}];
}

// Load live stock from sheet — NEVER trust the AI agent's stock number
const liveRows = $('Get Live Stock Sales1').all().map(i => i.json);
const liveMap = {};
for (const r of liveRows) {
  if (r.sku_id) liveMap[r.sku_id] = r;
}

return items.map(p => {
  let sku, name, qtySold, cat;
  if (Array.isArray(p)) {
    sku     = p[0];
    name    = p[1];
    qtySold = p[2];
    cat     = p[4] || 'General';
  } else {
    sku=p.sku_id; name=p.product_name||p.sku_id; qtySold=p.quantity_sold;
    cat=p.category||'General';
  }

  qtySold = (qtySold !== null && qtySold !== undefined && qtySold !== '' && qtySold !== '?')
            ? (parseInt(String(qtySold).replace(/[^0-9]/g,'')) || 0)
            : 0;
  name = name || sku || 'Unknown';
  cat  = (cat && cat !== 'undefined' && cat !== '') ? cat : 'General';

  // FIX: Get REAL stock from live sheet — ignore AI agent's claimed stock value
  const live = liveMap[sku];
  if (!live) {
    // SOFT ERROR instead of throw — SKU not found
    return {json:{
      __blocked: true,
      _block_msg: `\u274C "${name}" inventory mein exist nahi karta. Pehle purchase karein.`,
      sku_id:sku||'', product_name:name, category:cat,
      quantity_sold:'0', sale_date:today, source:'Chat', chat_id:'',
      stock_deducted:'0', processed_at:ts, message_text:`SKU_NOT_FOUND: ${sku}`,
      sale_datetime:ts, status:'BLOCKED', new_stock:'0', current_stock:'0', last_updated:ts
    }};
  }

  // Preserve category from sheet if agent didn't send one
  if (!cat || cat === 'General') {
    cat = live.category || 'General';
  }

  const liveStock = parseInt(String(live.current_stock).replace(/[^0-9]/g,'')) || 0;

  // SOFT ERROR instead of throw — zero stock block
  if (liveStock <= 0) {
    return {json:{
      __blocked: true,
      _block_msg: `\u274C "${name}" ka current stock 0 hai. Sale nahi ho sakti. Pehle purchase karein.`,
      sku_id:sku, product_name:name, category:cat,
      quantity_sold:'0', sale_date:today, source:'Chat', chat_id:'',
      stock_deducted:'0', processed_at:ts, message_text:`ZERO_STOCK_BLOCK: ${name}`,
      sale_datetime:ts, status:'BLOCKED', new_stock:String(liveStock), current_stock:String(liveStock), last_updated:ts
    }};
  }

  // Safety cap: can't sell more than available
  const safeQty  = qtySold > liveStock ? liveStock : qtySold;
  const newStock = String(Math.max(0, liveStock - safeQty));

  // Extract price_at_sale from batch index 5
  let priceAtSale = 0;
  if (Array.isArray(p) && p[5] !== undefined && p[5] !== null && p[5] !== '') {
    priceAtSale = parseFloat(String(p[5]).replace(/[^0-9.]/g,'')) || 0;
  } else if (p && p.price_at_sale !== undefined) {
    priceAtSale = parseFloat(String(p.price_at_sale).replace(/[^0-9.]/g,'')) || 0;
  }
  const totalAmount = priceAtSale * safeQty;

  return {json:{
    sku_id:        sku,
    product_name:  name,
    category:      cat,
    quantity_sold: String(safeQty),
    sale_date:     today,
    source:        'Chat',
    chat_id:       '',
    stock_deducted:String(safeQty),
    processed_at:  ts,
    message_text:  `${name} - ${safeQty} units sold`,
    sale_datetime: ts,
    status:        'PROCESSED',
    new_stock:     newStock,
    current_stock: newStock,
    last_updated:  ts,
    price_at_sale: String(priceAtSale),
    total_amount:  String(totalAmount)
  }};
});

const items = $input.first().json.products || [];
const total = items.length;
const preview = items.slice(0,10).map(p => {
  const name    = p.product_name || p.sku_id || '?';
  const cost    = p.cost_price    && p.cost_price    !== '0' ? ` | Cost: ₹${p.cost_price}`    : '';
  const selling = p.selling_price && p.selling_price !== '0' ? ` | Selling: ₹${p.selling_price}` : '';
  return `• ${name} (Qty: ${p.current_stock})${cost}${selling}`;
}).join('\n');
const more = total > 10 ? `\n...and ${total-10} more products` : '';
return [{json:{output:`✅ ${total}/${total} naye products inventory mein add ho gaye!\n\n${preview}${more}\n\n📦 Inventory Master → Updated\n📋 PO Tracker → Updated`}}];

const raw = $('Route Batch Type1').first().json.batch;
const today = new Date().toISOString().split('T')[0];
const ts    = new Date().toISOString();
let items, sn, sc;
if (!raw) {
  items = []; sn = ''; sc = '';
} else if (Array.isArray(raw)) {
  items = raw; sn=''; sc='';
} else {
  sn = raw.sn||''; sc = String(raw.sc||''); items = raw.p||[];
}

// FIX: Instead of throwing error, return empty pass-through so workflow doesn't crash
if (!items || items.length === 0) {
  return [{json:{
    sku_id: '',
    product_name: '',
    current_stock: '0',
    category: '',
    supplier_name: sn,
    supplier_contact_number: sc,
    _empty_batch: true,
    _reason: 'EMPTY_UNMATCHED_BATCH: no items recovered from agent output'
  }}];
}

// Build live sheet lookup by BOTH sku_id and normalized product_name
let liveMap_sku  = {};
let liveMap_name = {};

try {
  const liveRows = $('Get Live Stock Unmatched1').all().map(i => i.json);
  for (const r of liveRows) {
    if (r.sku_id) liveMap_sku[r.sku_id] = r;
    if (r.product_name) {
      const norm = String(r.product_name || '').toLowerCase().replace(/[^a-z0-9]/g, '').trim();
      liveMap_name[norm] = r;
    }
  }
} catch(e) { /* live read not in this path */ }

return items.map((p, i) => {
  let name, qty, sku, cat;
  if (Array.isArray(p)) {
    [name, qty] = p;
    qty = parseInt(qty) || 50;
    cat = p[2] || 'General';
  } else {
    sku  = p.sku_id;
    name = p.product_name || p.sku_id;
    qty  = parseInt(p.current_stock ?? p.quantity_ordered ?? 50) || 50;
    cat  = p.category || 'General';
    sn   = p.supplier_name || sn;
    sc   = String(p.supplier_contact_number || sc);
  }
  name = name || sku || 'Unknown';
  cat  = (cat && cat !== 'undefined' && cat !== '') ? cat : 'General';

  const normName = String(name || '').toLowerCase().replace(/[^a-z0-9]/g, '').trim();
  const existingByName = liveMap_name[normName];
  const existingBySku  = sku ? liveMap_sku[sku] : null;
  const existing = existingBySku || existingByName;

  if (existing) {
    const realSku   = existing.sku_id;
    const realCat   = existing.category || cat;
    const liveStock = parseInt(String(existing.current_stock).replace(/[^0-9]/g,'')) || 0;
    const newStock  = liveStock + qty;

    let costPrice = 0, sellingPrice = 0;
    if (Array.isArray(p)) {
      costPrice    = parseFloat(String(p[3]||0).replace(/[^0-9.]/g,''))||0;
      sellingPrice = parseFloat(String(p[4]||0).replace(/[^0-9.]/g,''))||0;
    } else {
      costPrice    = parseFloat(String(p.cost_price   ||0).replace(/[^0-9.]/g,''))||0;
      sellingPrice = parseFloat(String(p.selling_price||0).replace(/[^0-9.]/g,''))||0;
    }
    return {json:{
      sku_id:                 realSku,
      product_name:           existing.product_name || name,
      current_stock:          String(newStock),
      category:               realCat,
      supplier_name:          sn,
      supplier_contact_number:sc,
      created_at:             existing.created_at || today,
      last_updated:           ts,
      po_number:              `PO-${today.replace(/-/g,'')}-${String(i+1).padStart(4,'0')}`,
      quantity_ordered:       String(qty),
      po_date:                today,
      estimated_delivery:     today,
      po_status:              'ORDERED',
      forecasted_demand:      '0',
      days_until_stockout:    '0',
      stock_added:            'YES',
      stock_added_at:         ts,
      delivery_datetime:      ts,
      cost_price:             String(costPrice),
      selling_price:          String(sellingPrice),
      price_at_purchase:      String(costPrice),
      total_cost:             String(costPrice * qty)
    }};
  }

  if (!sku) {
    sku = 'SKU-' + name.toUpperCase().replace(/[^A-Z0-9]/g,'').slice(0,18) + '-' + String(i+1).padStart(4,'0');
  }
  let costPrice2 = 0, sellingPrice2 = 0;
  if (Array.isArray(p)) {
    costPrice2    = parseFloat(String(p[3]||0).replace(/[^0-9.]/g,''))||0;
    sellingPrice2 = parseFloat(String(p[4]||0).replace(/[^0-9.]/g,''))||0;
  } else {
    costPrice2    = parseFloat(String(p.cost_price   ||0).replace(/[^0-9.]/g,''))||0;
    sellingPrice2 = parseFloat(String(p.selling_price||0).replace(/[^0-9.]/g,''))||0;
  }
  return {json:{
    sku_id:                 sku,
    product_name:           name,
    current_stock:          String(qty),
    category:               cat,
    supplier_name:          sn,
    supplier_contact_number:sc,
    created_at:             today,
    last_updated:           ts,
    po_number:              `PO-${today.replace(/-/g,'')}-${String(i+1).padStart(4,'0')}`,
    quantity_ordered:       String(qty),
    po_date:                today,
    estimated_delivery:     today,
    po_status:              'ORDERED',
    forecasted_demand:      '0',
    days_until_stockout:    '0',
    stock_added:            'YES',
    stock_added_at:         ts,
    delivery_datetime:      ts,
    cost_price:             String(costPrice2),
    selling_price:          String(sellingPrice2),
    price_at_purchase:      String(costPrice2),
    total_cost:             String(costPrice2 * qty)
  }};
});

const out = ($input.first().json.output || '').trim();

const MARKERS = [
  {key:'purchase', tag:'PURCHASE_BATCH'},
  {key:'unmatched', tag:'UNMATCHED_BATCH'},
  {key:'sales',    tag:'SALES_BATCH'},
  {key:'stock_check', tag:'STOCK_CHECK'},
  {key:'delete',    tag:'DELETE_BATCH'}
];

function recoverJSON(str) {
  str = str.trim();
  try { return JSON.parse(str); } catch(_) {}
  const lastClose = str.lastIndexOf('}');
  if (lastClose >= 0) {
    let s = str.slice(0, lastClose + 1).replace(/,\s*$/, '');
    try { return JSON.parse(s); } catch(_) {}
  }
  // Compact-format recovery: extract complete elements from "p":[...]
  const pMatch = str.match(/"p"\s*:\s*\[/);
  if (pMatch) {
    const pArrayOpen = str.indexOf('[', str.indexOf(pMatch[0]));
    if (pArrayOpen >= 0) {
      const pContent = str.slice(pArrayOpen + 1);
      const elements = [];
      let depth = 0, elemStart = -1;
      for (let i = 0; i < pContent.length; i++) {
        const c = pContent[i];
        if (c === '[') { if (depth === 0) elemStart = i; depth++; }
        else if (c === ']') {
          depth--;
          if (depth === 0 && elemStart >= 0) {
            try { elements.push(JSON.parse(pContent.slice(elemStart, i + 1))); } catch(_) {}
            elemStart = -1;
          }
        }
      }
      if (elements.length > 0) {
        const snM = str.match(/"sn"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        const scM = str.match(/"sc"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        return { sn: snM ? snM[1] : '', sc: scM ? scM[1] : '', p: elements };
      }
    }
  }
  return [];
}

// Also handle numbered chunks: %%TAG_1%%, %%TAG_2%%...
const allMarkers = [];
for (const {key, tag} of MARKERS) {
  const regex = new RegExp(`%%(${tag}(?:_\\d+)?)%%`, 'g');
  let m;
  while ((m = regex.exec(out)) !== null) {
    allMarkers.push({ tag: m[1], key, pos: m.index });
  }
}
allMarkers.sort((a, b) => a.pos - b.pos);

const merged = {};
for (let i = 0; i < allMarkers.length; i++) {
  const { tag, key, pos } = allMarkers[i];
  const startTag = '%%' + tag + '%%';
  const afterStart = out.slice(pos + startTag.length);
  const ei = afterStart.indexOf('%%END%%');
  const nextPositions = allMarkers.slice(i+1).map(m => {
    const idx = out.indexOf('%%'+m.tag+'%%', pos+1);
    return idx >= 0 ? idx - pos - startTag.length : Infinity;
  }).filter(p => p > 0);
  const end = ei >= 0 ? ei : (nextPositions.length ? Math.min(...nextPositions) : afterStart.length);
  const jsonStr = afterStart.slice(0, end).trim();
  const batch = recoverJSON(jsonStr);

  let products = [], sn = '', sc = '';
  if (Array.isArray(batch)) { products = batch; }
  else if (batch && batch.p) { products = batch.p; sn = batch.sn||''; sc = batch.sc||''; }

  if (!merged[key]) merged[key] = { sn, sc, p: [] };
  if (sn) merged[key].sn = sn;
  if (sc) merged[key].sc = sc;
  merged[key].p.push(...products);
}

const cleanOutput = out.replace(/%%[A-Z_0-9]+%%[\s\S]*?%%END%%/g, '').trim();
const found = [];
for (const [key, data] of Object.entries(merged)) {
  if (data.p.length > 0) {
    found.push({json:{
      batch_type:  key,
      output:      cleanOutput,
      batch:       { sn: data.sn, sc: data.sc, p: data.p },
      batch_count: data.p.length
    }});
  }
}

if (found.length === 0) {
  return [{json:{batch_type:'none', output:out, batch:[], batch_count:0}}];
}

// SAFETY NET — Option 3 (SaleAndPurchase) / Option 4 (PurchaseAll) require TWO batches
// (sales+unmatched, or purchase+unmatched). If the model only emitted one and mentioned/started
// the other tag without a clean %%TAG%%...%%END%% match (truncation, malformed JSON, or it
// simply forgot), flag it instead of silently letting a partial transaction look successful.
const producedKeys = new Set(Object.keys(merged));
const expectedPairs = [
  { withKey: 'purchase', needsKey: 'unmatched', needsTag: 'UNMATCHED_BATCH' },
  { withKey: 'sales',    needsKey: 'unmatched', needsTag: 'UNMATCHED_BATCH' },
  { withKey: 'unmatched', needsKey: 'purchase', needsTag: 'PURCHASE_BATCH' },
  { withKey: 'unmatched', needsKey: 'sales',    needsTag: 'SALES_BATCH' }
];
for (const pair of expectedPairs) {
  if (producedKeys.has(pair.withKey) && !producedKeys.has(pair.needsKey)) {
    const mentionsOtherTag = out.includes(pair.needsTag);
    if (mentionsOtherTag) {
      found.push({json:{
        batch_type:  'incomplete_batch_warning',
        output:      cleanOutput,
        warning:     `Model started/mentioned ${pair.needsTag} but it never parsed cleanly (likely truncated or malformed). Produced "${pair.withKey}" batch only — this transaction may be incomplete.`,
        batch:       [],
        batch_count: 0
      }});
    }
  }
}

return found;

const expectedItems = $('Prepare Purchase Items1').all();
const actual = $input.all();
if (actual.length < expectedItems.length) {
  const expectedSkus = expectedItems.map(i => i.json.sku_id);
  const actualSkus = actual.map(i => i.json.sku_id);
  const missing = expectedSkus.filter(s => !actualSkus.includes(s));
  throw new Error(`PARTIAL_WRITE_FAILURE: missing SKUs in sheet update: ${missing.join(', ')}`);
}
// BUG FIX: Update Inventory Purchase1 (Google Sheets "update" op) only returns the 5 fields it
// was given (sku_id, product_name, current_stock, category, last_updated) — not the full PO
// record. Returning $input.all() here was passing that truncated data straight into
// Append PO Tracker Purchase1, producing PO Tracker rows missing po_number, quantity_ordered,
// po_date, supplier info, etc. Returning the original full Prepare Purchase Items1 data instead
// (count-verified above) ensures PO Tracker always gets the complete record, same as the
// structural/new-product path already does via Code in JavaScript1.
return expectedItems;

const raw = $('Route Batch Type1').first().json.batch;
const items = Array.isArray(raw) ? raw : (raw && raw.p ? raw.p : []);

if (!items || items.length === 0) {
  throw new Error('EMPTY_DELETE_BATCH: no items recovered from agent output');
}

const liveRows = $('Get Live Stock Delete1').all().map(i => i.json);
const liveMap = {};
for (const r of liveRows) {
  if (r.sku_id) liveMap[r.sku_id] = r;
}

const prepared = items.map(p => {
  let sku, name;
  if (Array.isArray(p)) {
    sku  = p[0];
    name = p[1];
  } else {
    sku  = p.sku_id;
    name = p.product_name || p.sku_id;
  }

  const live = liveMap[sku];
  if (!live) {
    throw new Error("SKU_NOT_FOUND_IN_LIVE_SHEET: " + sku + " (" + name + ") - inventory mein exist nahi karta, delete nahi ho sakta.");
  }

  const rowNumber = live.row_number;
  if (!rowNumber) {
    throw new Error("ROW_NUMBER_MISSING: " + sku + " (" + name + ") ka row number nahi mila - delete safely nahi ho sakta.");
  }

  return {
    sku_id: sku,
    product_name: live.product_name || name,
    category: live.category || 'General',
    row_number: rowNumber,
    startIndex: rowNumber - 1,
    deleted_at: new Date().toISOString()
  };
});

prepared.sort((a, b) => b.row_number - a.row_number);

return prepared.map(p => ({json: p}));

const items = $input.first().json.products || [];
const total = items.length;

const preview = items.slice(0,10).map(function(p){ return "- " + (p.product_name || p.sku_id); }).join("\n");
const more = total > 10 ? ("\n...and " + (total-10) + " more products") : "";

return [{json:{output: total + " product(s) inventory se delete ho gaye!\n\n" + preview + more + "\n\nInventory updated"}}];

